'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { collection, getDocs, query, where } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Project } from '@/lib/types';
import BottomNav from '@/components/BottomNav';

const TYPES = [
  { key: 'software', label: 'Software', icon: '💻' },
  { key: 'hardware', label: 'Hardware', icon: '🔧' },
  { key: 'non-technical', label: 'Non-Tech', icon: '🎭' },
];

const DOMAINS = [
  { key: 'healthcare', label: 'Healthcare', icon: '🏥' },
  { key: 'agriculture', label: 'Farming', icon: '🌾' },
  { key: 'travel', label: 'Travel', icon: '✈️' },
  { key: 'food', label: 'Food Tech', icon: '🍴' },
  { key: 'education', label: 'Education', icon: '📚' },
  { key: 'environment', label: 'Sustainability', icon: '🌱' },
  { key: 'finance', label: 'FinTech', icon: '💳' },
  { key: 'entertainment', label: 'Entertainment', icon: '🎮' },
];

export default function ProjectsPage() {
  const { user, profile, loading } = useAuth();
  const router = useRouter();
  const [projects, setProjects] = useState<Project[]>([]);
  const [recommended, setRecommended] = useState<{ id: string; score: number; name?: string }[]>([]);
  const [loadingProjects, setLoadingProjects] = useState(false);
  const [selectedTypes, setSelectedTypes] = useState<string[]>([]);
  const [selectedDomains, setSelectedDomains] = useState<string[]>([]);
  const [view, setView] = useState<'categories' | 'feed' | 'recommended'>('categories');
  const [interested, setInterested] = useState<Record<string, boolean>>({});
  const [searchQuery, setSearchQuery] = useState('');
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    if (!loading && !user) router.push('/auth');
  }, [user, loading, router]);

  // Load semantic recommendations once on mount
  useEffect(() => {
    if (!profile) return;
    const loadRecommended = async () => {
      try {
        const candidateText = [
          profile.headline ?? '',
          profile.aboutMe ?? '',
          (profile.techSkills ?? []).join(', '),
          (profile.nonTechSkills ?? []).join(', '),
        ].join('. ');
        const res = await fetch('/api/pinecone', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'search-projects', payload: { candidateText, topK: 5 } }),
        });
        if (res.ok) {
          const { matches } = await res.json();
          setRecommended(matches ?? []);
        }
      } catch { /* graceful */ }
    };
    loadRecommended();
  }, [profile]);

  const fetchProjects = async () => {
    setLoadingProjects(true);
    try {
      const snap = await getDocs(collection(db, 'projects'));
      let all = snap.docs.map((d) => ({ id: d.id, ...d.data() } as Project));
      if (selectedTypes.length > 0) all = all.filter((p) => selectedTypes.includes(p.category));
      if (selectedDomains.length > 0) all = all.filter((p) => selectedDomains.includes(p.domain));
      setProjects(all);
      setView('feed');
    } catch (err) { console.error(err); }
    finally { setLoadingProjects(false); }
  };

  const filteredProjects = view === 'feed'
    ? projects.filter((p) =>
      !searchQuery ||
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.description?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (p.tags ?? []).some((t: string) => t.toLowerCase().includes(searchQuery.toLowerCase()))
    )
    : [];

  const toggleType = (t: string) =>
    setSelectedTypes((prev) => prev.includes(t) ? prev.filter((x) => x !== t) : [...prev, t]);
  const toggleDomain = (d: string) =>
    setSelectedDomains((prev) => prev.includes(d) ? prev.filter((x) => x !== d) : [...prev, d]);

  const sendInterest = (id: string) => {
    setInterested((prev) => ({ ...prev, [id]: true }));
    setToast('Interest sent! ✓');
    setTimeout(() => setToast(null), 2200);
  };

  if (loading) return <div className="loading-page"><div className="spinner" /></div>;

  return (
    <div className="app-shell">
      <header className="c-header">
        <span className="c-logo">Campus<span>Link</span></span>
        <button
          className="notif-btn"
          onClick={() => router.push('/projects/create')}
          title="Post a project"
        >
          +
        </button>
      </header>

      <div className="page-content">
        <div className="projects-wrap">
          {view === 'categories' ? (
            <>
              <h1 className="section-title">Projects</h1>
              <p className="section-sub">Find your next collaboration</p>

              {/* Semantic recommendations */}
              {recommended.length > 0 && (
                <div style={{ marginBottom: 24 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                    <div className="domain-label">Recommended for You</div>
                    <span className="nim-badge">✦ AI Matched</span>
                  </div>
                  {recommended.map((r) => (
                    <div
                      key={r.id}
                      className="project-card"
                      style={{ marginBottom: 10, cursor: 'pointer' }}
                      onClick={() => router.push(`/projects/${r.id}`)}
                    >
                      <div className="pc-top">
                        <div className="pc-name">{String(r.name ?? 'Project')}</div>
                        <div style={{ fontSize: 11, color: 'var(--subtle)' }}>{((r.score ?? 0) * 100).toFixed(0)}% match</div>
                      </div>
                      <button className="interested-btn" onClick={(e) => { e.stopPropagation(); router.push(`/projects/${r.id}`); }}>
                        View →
                      </button>
                    </div>
                  ))}
                  <div className="divider" />
                </div>
              )}

              <div className="type-grid">
                {TYPES.map((t) => (
                  <div key={t.key} className={`type-card ${selectedTypes.includes(t.key) ? 'active' : ''}`} onClick={() => toggleType(t.key)}>
                    <div className="icon">{t.icon}</div>
                    <div className="label">{t.label}</div>
                  </div>
                ))}
              </div>

              <div className="domain-label">Domains</div>
              <div className="domain-grid">
                {DOMAINS.map((d) => (
                  <div key={d.key} className={`domain-card ${selectedDomains.includes(d.key) ? 'active' : ''}`} onClick={() => toggleDomain(d.key)}>
                    <span className="di">{d.icon}</span>
                    <span className="dn">{d.label}</span>
                  </div>
                ))}
              </div>

              <button className="browse-btn" onClick={fetchProjects}>
                {loadingProjects ? 'Loading...' : 'Browse All Projects →'}
              </button>

              <button className="edit-profile-btn" onClick={() => router.push('/projects/my')}>
                My Projects
              </button>
            </>
          ) : (
            <>
              <div className="feed-header">
                <button className="back-btn" onClick={() => setView('categories')}>← Back</button>
                <span className="filter-chip">{filteredProjects.length} projects</span>
              </div>

              <input
                className="chat-input"
                style={{ width: '100%', borderRadius: 12, marginBottom: 16 }}
                placeholder="Search by name, skill, or keyword..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />

              {filteredProjects.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--subtle)' }}>
                  No projects found.{' '}
                  <button className="back-btn" onClick={() => setView('categories')}>Adjust filters</button>
                </div>
              ) : filteredProjects.map((p) => (
                <div key={p.id} className="project-card" onClick={() => router.push(`/projects/${p.id}`)}>
                  <div className="pc-top">
                    <div className="pc-name">{p.name}</div>
                    <div className={`pc-badge ${p.isHackathon ? 'hackathon' : ''}`}>
                      {p.isHackathon ? 'Hackathon' : p.isCompetition ? 'Competition' : p.status}
                    </div>
                  </div>
                  <div className="pc-desc">{p.description}</div>
                  <div className="pc-tags">
                    {(p.desiredSkills ?? p.tags ?? []).slice(0, 5).map((t: string) => (
                      <span key={t} className="pc-tag">{t}</span>
                    ))}
                  </div>
                  <div className="pc-footer">
                    <div className="pc-meta">by {p.ownerCodeName} · {p.approvedUsers?.length ?? 0}/{p.teamSize} members</div>
                    <button
                      className={`interested-btn ${interested[p.id] ? 'sent' : ''}`}
                      onClick={(e) => { e.stopPropagation(); !interested[p.id] && sendInterest(p.id); }}
                    >
                      {interested[p.id] ? '✓ Noted' : 'View →'}
                    </button>
                  </div>
                </div>
              ))}
            </>
          )}
        </div>
      </div>

      {toast && <div className="toast">{toast}</div>}
      <BottomNav />
    </div>
  );
}
